create table if not exists public.organization_expenses (id uuid primary key default gen_random_uuid(),vendor text not null check(char_length(vendor) between 1 and 160),description text not null check(char_length(description) between 1 and 240),category text not null default 'other' check(category in('equipment','uniforms','tournament','facility','travel','marketing','insurance','professional','office','other')),amount_cents integer not null check(amount_cents>0),expense_date date not null default current_date,payment_method text not null default 'other' check(payment_method in('cash','check','card','bank_transfer','venmo','cash_app','other')),reference text not null default '',notes text not null default '',status text not null default 'posted' check(status in('posted','void')),created_by uuid not null references auth.users(id),created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create index if not exists organization_expenses_date_idx on public.organization_expenses(expense_date desc);alter table public.organization_expenses enable row level security;drop policy if exists "Executives manage organization expenses" on public.organization_expenses;create policy "Executives manage organization expenses" on public.organization_expenses for all to authenticated using(exists(select 1 from public.organization_members m where m.user_id=auth.uid() and m.active and m.role in('executive','admin'))) with check(exists(select 1 from public.organization_members m where m.user_id=auth.uid() and m.active and m.role in('executive','admin')));grant select,insert,update,delete on public.organization_expenses to authenticated;
